// Calculate the period for this brief
const periodDays = parseInt(process.env.BRIEF_PERIOD_DAYS || '7');
const periodEnd = new Date();
const periodStart = new Date(periodEnd.getTime() - periodDays * 24 * 60 * 60 * 1000);

return [{
  json: {
    period_start: periodStart.toISOString(),
    period_end: periodEnd.toISOString(),
    period_days: periodDays,
    period_label: `${periodStart.toISOString().substring(0, 10)} → ${periodEnd.toISOString().substring(0, 10)}`,
    company: process.env.COMPANY_NAME || 'Your Company',
    include_github: process.env.BRIEF_INCLUDE_GITHUB !== 'false',
    github_owner: process.env.GITHUB_OWNER || '',
    github_repo: process.env.GITHUB_REPO || '',
  }
}];

// Filter to PRs merged within the brief period
const prs = $input.all().map(i => i.json);
const period = $('Initialise Brief Period').first().json;
const periodStart = new Date(period.period_start);

const mergedThisWeek = prs
  .filter(pr => {
    if (!pr.merged_at) return false;
    return new Date(pr.merged_at) >= periodStart;
  })
  .map(pr => ({
    number: pr.number,
    title: pr.title,
    author: pr.user?.login,
    merged_at: pr.merged_at,
    labels: (pr.labels || []).map(l => l.name),
    url: pr.html_url,
  }));

console.log(`GitHub: ${mergedThisWeek.length} PRs merged this period`);

return [{ json: { github_prs: mergedThisWeek, source: 'github' } }];

// Collect manual data — in production this reads from Google Sheets
// This demo uses embedded sample data

// TODO (production): Replace with a Google Sheets 'Get Many' node
// to read the current week's row from your metrics sheet

const manualData = {
  shipped: [
    "Dark mode released to all users",
    "API response time reduced by 35% after CDN optimisation",
    "New onboarding checklist launched"
  ],
  metric_changes: [
    { metric: "Weekly Active Users", previous: 1240, current: 1380, change_pct: 11.3, trend: "up" },
    { metric: "Avg. Session Duration", previous: "4m 12s", current: "4m 38s", change_pct: 10.3, trend: "up" },
    { metric: "Support tickets opened", previous: 87, current: 62, change_pct: -28.7, trend: "down" }
  ],
  customer_insights: [
    "5 enterprise customers requested bulk export — follow up with Sales",
    "Onboarding completion rate up 15% after checklist launch"
  ],
  blockers: [
    { blocker: "Design review for v2 billing page", owner: "Design team", due: "2025-01-20" },
    { blocker: "Legal approval for new ToS", owner: "Legal", due: "2025-01-25" }
  ],
  scope_changes: [
    "SSO feature moved from Q1 to Q2 due to security review"
  ],
  risks: [
    "Dependency on third-party payment provider — they announced pricing changes"
  ],
  decisions_required: [
    { question: "Sunset the legacy CSV export format?", context: "Only 3% of users use it, high maintenance cost", deadline: "2025-01-24" }
  ],
  priorities_next_week: [
    "Finish v2 billing page (unblocked once design review done)",
    "Start SSO vendor evaluation",
    "Review and prioritise the 15 new feature requests from feedback report"
  ]
};

return [{ json: { manual_data: manualData, source: 'manual' } }];

// Merge all data sources into a single brief input
const githubData = $('Filter Merged PRs This Period').first()?.json ||
                   $('Skip GitHub (not configured)').first()?.json ||
                   { github_prs: [] };

const manualData = $('Collect Manual Data (Sheets)').first().json.manual_data;
const period = $('Initialise Brief Period').first().json;

// Build the AI prompt input
const briefInput = {
  period: period.period_label,
  company: period.company,
  github_prs_merged: githubData.github_prs || [],
  shipped: manualData.shipped || [],
  metric_changes: manualData.metric_changes || [],
  customer_insights: manualData.customer_insights || [],
  blockers: manualData.blockers || [],
  scope_changes: manualData.scope_changes || [],
  risks: manualData.risks || [],
  decisions_required: manualData.decisions_required || [],
  priorities_next_week: manualData.priorities_next_week || [],
};

console.log(`Merging data: ${briefInput.github_prs_merged.length} PRs, ${briefInput.shipped.length} shipped, ${briefInput.blockers.length} blockers`);

return [{ json: briefInput }];

// Parse AI response and enrich with metadata
const aiResponse = $input.first().json;
const period = $('Initialise Brief Period').first().json;

let rawContent;
try {
  rawContent = aiResponse?.message?.content ||
               aiResponse?.choices?.[0]?.message?.content ||
               aiResponse?.content ||
               JSON.stringify(aiResponse);
} catch (e) {
  throw new Error('Could not extract AI response content');
}

let brief;
try {
  brief = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (e) {
  throw new Error(`Could not parse AI brief JSON: ${e.message}`);
}

// Enrich with metadata
brief.meta = {
  period: period.period_label,
  company: period.company,
  generated_at: new Date().toISOString(),
  n8n_version: '2.30.0',
};

const healthEmoji = { green: '🟢', yellow: '🟡', red: '🔴' }[brief.overall_health] || '⚪';
brief.health_emoji = healthEmoji;

console.log(`Brief generated: health=${brief.overall_health}, ${brief.what_shipped?.length} shipped, ${brief.decisions_required?.length} decisions needed`);

return [{ json: brief }];

// Format the brief as a notification message
const approval = $input.first().json;
const brief = $('Parse and Enrich Brief').first().json;

const shipped = (brief.what_shipped || []).map((s, i) => `${i + 1}. ${s}`).join('\n');
const blockers = (brief.current_blockers || []).map(b => `• ${b.blocker} (${b.urgency})`).join('\n');
const decisions = (brief.decisions_required || []).map(d => `• ${d.question} — deadline: ${d.deadline}`).join('\n');
const priorities = (brief.priorities_next_week || []).map((p, i) => `${i + 1}. ${p}`).join('\n');

const metricLines = (brief.important_metric_changes || []).map(m => `• ${m.metric}: ${m.change} — ${m.significance}`).join('\n');

const body = `
${brief.health_emoji} **Weekly Product Brief — ${brief.meta.company}**
📅 ${brief.meta.period}

**Executive Summary:**
${brief.executive_summary}

**What Shipped:**
${shipped || 'Nothing merged this week'}

**Key Metrics:**
${metricLines || 'No metric changes logged'}

**Customer Insights:**
${(brief.customer_insights || []).map(i => `• ${i}`).join('\n') || 'None this week'}

**Blockers:**
${blockers || 'No blockers 🎉'}

**Decisions Required:**
${decisions || 'No decisions pending'}

**Next Week Priorities:**
${priorities}
`.trim();

return [{
  json: {
    channel: process.env.NOTIFICATION_CHANNEL || 'email',
    title: `${brief.health_emoji} Weekly Brief — ${brief.meta.company} ${brief.meta.period}`,
    body,
    urgency: brief.overall_health === 'red' ? 'high' : brief.overall_health === 'yellow' ? 'medium' : 'low',
    metadata: { period: brief.meta.period }
  }
}];

const approval = $input.first().json;
console.log(`Brief ${approval.decision}: ${approval.comment || 'no comment'}`);
return [{ json: { logged: true, decision: approval.decision } }];
